// DEBOUNCE CHECK v15 - Atomic latest-message validation
const mergedData = $('Merge Input').first().json;
const saveNode = $('Save Incoming Message').first();

let ourId = null;
const savedBody = saveNode.json;

if (Array.isArray(savedBody)) {
  if (savedBody.length > 0 && savedBody[0]?.id !== undefined) {
    ourId = savedBody[0].id;
  }
} else if (savedBody && typeof savedBody === 'object') {
  if (savedBody.id !== undefined) {
    ourId = savedBody.id;
  }
}

if (ourId === null || ourId === undefined) {
  return [{ json: { ...mergedData, should_continue: false, debug: 'could_not_extract_saved_message_id' } }];
}

const rpcResult = $('Check Is Latest (RPC)').first().json;

let isLatest = false;
if (typeof rpcResult === 'boolean') {
  isLatest = rpcResult;
} else if (Array.isArray(rpcResult) && rpcResult.length > 0) {
  isLatest = rpcResult[0] === true || rpcResult[0]?.check_is_latest_message === true;
} else if (rpcResult && typeof rpcResult === 'object') {
  isLatest = rpcResult.check_is_latest_message === true || rpcResult.result === true;
}

if (!isLatest) {
  return [{ json: { ...mergedData, should_continue: false, debug: 'not_latest' } }];
}

return [{ json: { ...mergedData, should_continue: true, our_id: ourId } }];

// MERGE & AGGREGATE consecutive user bursts v15
const mergedData = $('Debounce Check').first().json;

let recentRaw = [];
try {
  recentRaw = $('Fetch Recent Messages').all();
} catch (e) {
  recentRaw = [];
}

const byId = new Map();
for (const item of recentRaw) {
  const payload = item.json;
  const rows = Array.isArray(payload) ? payload : [payload];
  for (const row of rows) {
    if (!row || row.id === undefined || row.id === null) continue;
    byId.set(row.id, row);
  }
}

const recentMessages = [...byId.values()]
  .sort((a, b) => new Date(a.created_at || 0) - new Date(b.created_at || 0));

if (recentMessages.length === 0) {
  return [{ json: { ...mergedData, messages_merged: 1 } }];
}

const latestId = mergedData.our_id;
let latestIndex = recentMessages.findIndex((row) => String(row.id) === String(latestId));
if (latestIndex === -1) latestIndex = recentMessages.length - 1;

const burst = [];
for (let i = latestIndex; i >= 0; i--) {
  const row = recentMessages[i];
  if (!row || row.role !== 'user') break;
  const text = String(row.message || '').trim();
  if (text && text !== '(vacío)') burst.unshift(text);
}

const combined = burst.join(' ').trim();

return [{
  json: {
    ...mergedData,
    user_message: combined || mergedData.user_message,
    messages_merged: Math.max(burst.length, 1)
  }
}];

// Orchestrator v15 - Keyword routing with anti-overroute
if ($input.context.itemIndex > 0) return [];

const merged = $('Merge & Aggregate Messages').first().json;

let customerData = {};
try {
  const raw = $('Fetch Customer Profile').first().json;
  if (Array.isArray(raw) && raw.length > 0) customerData = raw[0];
  else if (raw && raw.manychat_id) customerData = raw;
} catch (e) { customerData = {}; }

let historyRows = [];
try {
  const items = $('Fetch Conversation History').all();
  for (const item of items) {
    const d = item.json;
    if (Array.isArray(d)) historyRows.push(...d);
    else if (d && d.role && d.message) historyRows.push(d);
  }
} catch (e) { historyRows = []; }

let productRows = [];
let productImages = {};
let productKeyNameMap = {};
let productStockMap = {};
let productConditionMap = {};
try {
  const items = $('Fetch Products').all();
  for (const item of items) {
    let d = item.json;
    if (d && d.data && Array.isArray(d.data)) d = d.data;
    const rows = Array.isArray(d) ? d : (d ? [d] : []);
    for (const p of rows) {
      if (!p || !p.product_key) continue;
      productRows.push(p);
      const baseName = String(p.product_name || '').trim();
      const cond = String(p.condition || 'new').trim().toLowerCase();
      const variantBits = [];
      if (cond === 'used') variantBits.push('seminuevo');
      else if (cond === 'like_new') variantBits.push('como nuevo');
      else if (cond === 'refurbished') variantBits.push('reacondicionado');
      else variantBits.push('nuevo');
      if (p.battery_health) variantBits.push('batería ' + p.battery_health + '%');
      productKeyNameMap[p.product_key] = baseName + ' (' + variantBits.join(', ') + ')';
      productStockMap[p.product_key] = p.in_stock;
      productConditionMap[p.product_key] = cond;
      const url = p.image_url || p.image || p.url;
      if (url && String(url).startsWith('http')) productImages[p.product_key] = String(url).trim();
    }
  }
} catch (e) { productRows = []; }

const humanAssigned = merged.is_human_active === true || customerData.human_assigned === true;
const isFirstInteraction = historyRows.length === 0;
const msg = String(merged.user_message || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const currentStage = String(customerData.funnel_stage || merged.funnel_stage || '').trim().toLowerCase();
const historyRowsSorted = [...historyRows]
  .sort((a, b) => new Date(a.created_at || 0) - new Date(b.created_at || 0));
const recentContextText = historyRowsSorted
  .slice(-6)
  .map((row) => String(row.message || ''))
  .join(' ')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '');
const hasTrackedProduct = !!String(customerData.interested_product || merged.interested_product || '').trim();
const hasActiveSalesStage = ['interested', 'closing'].includes(currentStage);
const hasRecentSalesContext = /(iphone|samsung|redmi|poco|pro max|bateria|gb|de contado|contado|cable y cargador|nuevo|seminuevo|como nuevo|\$\s*\d)/.test(recentContextText);
const looksLikeClosingFollowup = /(transfer|transferencia|debito|credito|efectivo|bitcoin|usdt|tarjeta|pago|pagar|contado|envio|despacho|sucursal|retiro|entrega|oran|salta|capital|soy de|soy del interior|me lo mandas|reservo|reserva|sena|seña)/.test(msg);
const shouldKeepSalesContext = looksLikeClosingFollowup && (hasTrackedProduct || hasActiveSalesStage || hasRecentSalesContext);

const patterns = {
  shipping: /ubicaci|direcci|local|donde est|horari|abierto|cerrado|atiend|cu[a\u00e1]ndo abr|envio|env\u00edo|mandan|despach|tracking|seguimiento|rastreo|llega|entrega|llegada|demora|d[i\u00ed]as|cuantos dias|pago|pagar|transfer|efectivo|crypto|bitcoin|usdt|tarjeta|debito|credito|mercado pago|instagram|facebook|rrss|garant[i\u00ed]a|servicio t[e\u00e9]cnico|reparaci[o\u00f3]n/,
  cuotas: /cuota|financi|plazo|mensual|bancariz|macro|6 cuotas|en cuotas|a cuotas|pagar en|naranja|subcredito|sucredito|su credito|tarjeta bancarizada/,
  catalog: /que tienen|qu[e\u00e9] tienen|que modelos|qu[e\u00e9] modelos|que hay|lista|cat[a\u00e1]log|precios de|todos los|ver todo|ver los|tienen iphone|tienen samsung|tienen redmi|tienen poco/,
  sales: /precio|cuanto sale|cu[a\u00e1]nto sale|cuesta|vale|sale el|tiene el|stock|hay|disponible|tenes el|ten[e\u00e9]s el|quiero el|me das|s25|s24|iphone 16|iphone 15|a56|a55|redmi|poco/,
  closing: /lo quiero|quiero comprarlo|c[o\u00f3]mo compro|me lo llevo|dale va|ok lo tomo|voy a llevar|quiero pedirlo|c[o\u00f3]mo pago|para pedir|para comprar/,
  handoff: /hablar con|habla con|joaco|joaqu[i\u00ed]n|una persona|un humano|un asesor|me atienda|ya pagu[e\u00e9]|mi pedido|cuando llega mi|retiro|busco mi|reclamo|queja|devoluci[o\u00f3]n|problema/
};

const matches = {};
let matchCount = 0;
for (const [key, pattern] of Object.entries(patterns)) {
  if (pattern.test(msg)) { matches[key] = true; matchCount++; }
}

let route;
if (humanAssigned) route = 'skip';
else if (isFirstInteraction && (!msg || msg === '(vacio)' || msg === '(mensaje vacio - el cliente abrio el chat)')) route = 'greeting';
else if (shouldKeepSalesContext) route = 'sales';
else if (matchCount >= 2) route = 'sales';
else if (matches.handoff) route = 'handoff';
else if (matches.closing) route = 'sales';
else if (matches.cuotas) route = 'cuotas';
else if (matches.shipping) route = 'shipping';
else if (matches.catalog) route = 'catalog';
else if (matches.sales) route = 'sales';
else route = 'sales';

let response_text = null;
let chatInput = null;
let needs_human = false;
let is_silent = false;

if (route === 'skip') {
  is_silent = true;
} else if (route === 'greeting') {
  response_text = '\ud83d\ude0a \u00a1Hola ' + merged.first_name + '! \u00bfC\u00f3mo and\u00e1s? Bienvenido a TechnoStore Salta \ud83d\udc4b\nContame qu\u00e9 celular est\u00e1s buscando o con qu\u00e9 te puedo ayudar, te atiendo al toque.';
} else if (route === 'handoff') {
  response_text = 'Te paso con un asesor que te va a ayudar \ud83d\ude4c';
  needs_human = true;
} else if (route === 'cuotas') {
  const mentionsNaranja = /naranja/i.test(msg);\n  const mentionsSubcredito = /subcredito|sucredito|su credito/i.test(msg);\n  if (mentionsNaranja || mentionsSubcredito) {\n    const rejected = mentionsNaranja && mentionsSubcredito ? 'Naranja ni SubCr\u00e9dito' : mentionsNaranja ? 'Naranja' : 'SubCr\u00e9dito';\n    response_text = 'Lamentablemente no trabajamos con ' + rejected + ' \ud83d\ude15 Pero aceptamos todas las dem\u00e1s tarjetas bancarizadas en 6 cuotas fijas, y Macro con precios especiales \ud83d\udcaa Son solo presenciales en Salta Capital. \u00bfQu\u00e9 modelo te interesa? As\u00ed te paso el detalle';\n  } else {\n    response_text = 'Manejamos cuotas con todas las tarjetas bancarizadas (excepto Naranja y SubCr\u00e9dito) en 6 cuotas fijas, y Macro con precios especiales \ud83d\udcaa Son solo presenciales en Salta Capital. \u00bfQu\u00e9 modelo te interesa y est\u00e1s en Salta? As\u00ed te paso el detalle exacto \ud83d\udcf1';\n  }
} else if (route === 'shipping') {
  const info = {
    ubicacion: '\ud83d\udccd Caseros 1365, Salta Capital. Diagonal a OCA, enfrente del Sindicato de Camioneros.',
    horarios: '\ud83d\udd50 Lunes a Viernes: 10:00-13:00 y 18:00-21:00 | S\u00e1bados: 10:00-13:00 | Domingos: cerrado.',
    pagos: '\ud83d\udcb3 Medios de pago: transferencia bancaria en pesos, transferencia en d\u00f3lares, Bitcoin y USDT (TRC-20) con 0% recargo, y efectivo en pesos o d\u00f3lares (solo Salta Capital). \u274c No hacemos cr\u00e9ditos personales.',
    envios: '\ud83d\udce6 Env\u00edos GRATIS a sucursal (BusPack/Flecha Carga, OCA o V\u00eda Cargo). Despacho en 72hs h\u00e1biles. Salta Capital: entrega en el d\u00eda. Interior Salta: 24hs.',
    garantia: 'La mayor\u00eda de los equipos son nuevos, sellados y con garant\u00eda oficial. Algunos modelos pueden ser semi-nuevos (como nuevo) \u2014 preguntame por el modelo que te interesa y te confirmo.'
  };
  if (/garant[i\u00ed]a|servicio t[e\u00e9]cnico|reparaci[o\u00f3]n/.test(msg)) response_text = info.garantia;
  else if (/tracking|seguimiento|rastreo/.test(msg)) response_text = info.envios;
  else if (/envio|env\u00edo|mandan|despach|llega|entrega|llegada|demora|d[i\u00ed]as|cuantos dias/.test(msg)) response_text = info.envios;
  else if (/pago|pagar|transfer|efectivo|crypto|bitcoin|usdt|tarjeta|debito|credito|mercado pago/.test(msg)) response_text = info.pagos;
  else if (/horari|abierto|cerrado|atiend|cu[a\u00e1]ndo abr/.test(msg)) response_text = info.horarios;
  else if (/ubicaci|direcci|local|donde est/.test(msg)) response_text = info.ubicacion;
  else if (/instagram|facebook|rrss/.test(msg)) response_text = '\ud83d\udcf1 Instagram y Facebook: @technostore.salta';
  else response_text = info.ubicacion + '\n' + info.horarios + '\n' + info.pagos + '\n' + info.envios;
}

if (route === 'sales' || route === 'catalog') {
  historyRows.sort((a, b) => new Date(a.created_at) - new Date(b.created_at));
  let historyText = historyRows.length > 0
    ? historyRows.map(h => {
        const role = h.role === 'user' ? 'CLIENTE' : h.role === 'bot' ? 'TECHNOBOT' : 'ASESOR';
        const time = h.created_at ? new Date(h.created_at).toLocaleString('es-AR', { timeZone: 'America/Argentina/Salta' }) : '';
        return '[' + role + '] ' + time + ': ' + h.message;
      }).join('\n')
    : '(Primera interacci\u00f3n)';

  let profileText = '(Cliente nuevo)';
  if (customerData.manychat_id) {
    const parts = [];
    if (customerData.city) parts.push('Ciudad: ' + customerData.city);
    if (customerData.is_salta_capital != null) parts.push('Salta: ' + (customerData.is_salta_capital ? 'S\u00cd' : 'NO'));
    if (customerData.preferred_brand) parts.push('Marca: ' + customerData.preferred_brand);
    if (customerData.interested_product) parts.push('Inter\u00e9s: ' + customerData.interested_product);
    if (customerData.funnel_stage) parts.push('Etapa: ' + customerData.funnel_stage);
    parts.push('Interacciones: ' + (customerData.total_interactions || 1));
    profileText = parts.join(' | ');
  }

  const productsByCategory = {};
  for (const p of productRows) {
    const cat = p.category || 'GENERAL';
    if (!productsByCategory[cat]) productsByCategory[cat] = [];
    const specs = [];
    if (p.ram_gb) specs.push(p.ram_gb + 'GB RAM');
    if (p.storage_gb) specs.push(p.storage_gb + 'GB');
    if (p.network) specs.push(String(p.network).toUpperCase());
    if (p.color) specs.push(p.color);
    const ss = specs.length > 0 ? ' (' + specs.join(', ') + ')' : '';
    let line = p.product_name + ss + ' \u2014 $' + Number(p.price_ars).toLocaleString('es-AR');
    if (p.promo_price_ars) line += ' | PROMO: $' + Number(p.promo_price_ars).toLocaleString('es-AR');
    if (p.price_usd) line += ' (USD ' + p.price_usd + ')';
    const cond = String(p.condition || 'new').toLowerCase();
    const condLabel = cond === 'used' ? 'SEMINUEVO' : cond === 'like_new' ? 'COMO NUEVO' : cond === 'refurbished' ? 'REACONDICIONADO' : 'NUEVO';
    line += ' | Estado: ' + condLabel;
    if (p.battery_health) line += ' | Batería: ' + p.battery_health + '%';
    if (cond === 'used' || cond === 'like_new' || cond === 'refurbished') line += ' | Incluye cable y cargador';
    if (p.delivery_type === 'on_order') line += ' [A PEDIDO - ' + p.delivery_days + ' d\u00edas]';
    if (p.in_stock === false) line += ' [SIN STOCK]';
    if (p.bancarizada_cuota) line += ' | Bancarizada 6c: $' + Number(p.bancarizada_cuota).toLocaleString('es-AR');
    if (p.macro_cuota) line += ' | Macro 6c: $' + Number(p.macro_cuota).toLocaleString('es-AR');
    line += ' | KEY: ' + p.product_key;
    productsByCategory[cat].push(line);
  }

  let inventoryText = '';
  for (const [cat, prods] of Object.entries(productsByCategory)) {
    inventoryText += '\n[' + cat + ']\n' + prods.join('\n') + '\n';
  }

  chatInput = '[CLIENTE: ' + merged.first_name + ']\n' +
    '[MENSAJE: ' + (merged.user_message || '(vac\u00edo)') + ']\n' +
    (merged.was_audio ? '[NOTA: Audio transcripto]\n' : '') +
    '[PRIMERA INTERACCI\u00d3N: ' + (isFirstInteraction ? 'S\u00cd' : 'NO') + ']\n' +
    '[HORA: ' + new Date().toLocaleString('es-AR', { timeZone: 'America/Argentina/Salta', weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit' }) + ']\n\n' +
    '[PERFIL] ' + profileText + '\n\n' +
    '[HISTORIAL]\n' + historyText + '\n\n' +
    '[INVENTARIO (' + productRows.length + ' productos)]\n' + inventoryText;
}

return [{
  json: {
    route,
    response_text,
    chatInput,
    is_silent,
    needs_human,
    subscriber_id: merged.subscriber_id,
    first_name: merged.first_name,
    phone: merged.phone,
    user_message: merged.user_message,
    was_audio: merged.was_audio,
    customer_id: customerData.id || null,
    customer_profile: customerData,
    product_images: productImages,
    product_key_name_map: productKeyNameMap,
    product_stock_map: productStockMap,
    product_condition_map: productConditionMap,
    is_first_interaction: isFirstInteraction
  }
}];

// Process Static Response - Build ManyChat payload for non-AI routes
const data = $input.first().json;
const route = data.route;
const responseText = data.response_text || '';

let intent = 'greeting';
let funnel_update = 'no_change';
if (route === 'shipping') { intent = 'shipping_inquiry'; }
else if (route === 'cuotas') { intent = 'cuotas_inquiry'; }
else if (route === 'handoff') { intent = 'complaint'; funnel_update = 'human_handoff'; }
else if (route === 'greeting') { intent = 'greeting'; funnel_update = 'new'; }

const metadata = {
  intent,
  products: 'none',
  funnel_update,
  city_detected: 'none',
  is_salta: 'unknown',
  brand_interest: 'none',
  budget_hint: 'none'
};

const payload = {
  subscriber_id: data.subscriber_id,
  data: {
    version: 'v2',
    content: {
      type: 'whatsapp',
      messages: [{ type: 'text', text: responseText }]
    }
  }
};

return [{
  json: {
    is_silent: false,
    payload,
    needs_human: data.needs_human || false,
    clean_text: responseText,
    metadata,
    products_list: [],
    subscriber_id: data.subscriber_id,
    user_message: data.user_message,
    was_audio: data.was_audio,
    customer_id: data.customer_id,
    current_funnel_stage: data.customer_profile?.funnel_stage || null
  }
}];

const query = $input.first().json.query || '';
const q = String(query || '').toLowerCase();

let esSalta = null;
const saltaMatch = q.match(/salta[:\s]*(true|false|si|sí|no|unknown)/i);
if (saltaMatch) {
  const val = saltaMatch[1].toLowerCase();
  esSalta = (val === 'true' || val === 'si' || val === 'sí');
}

if (esSalta === false) {
  return 'Las cuotas son SOLO presenciales en Salta Capital. Para envíos a otras ciudades las opciones son transferencia bancaria (pesos o dólares), Bitcoin/USDT (0% recargo) o efectivo presencial. No se puede hacer cuotas por envío.';
}

if (esSalta === null) {
  return 'Necesito confirmar si estás en Salta Capital para calcular cuotas, porque las cuotas son solo presenciales en Salta Capital.';
}

const hasModelHint = /(iphone|samsung|redmi|poco|xiaomi|a\d{2}|s\d{2}|\d\+\d{3}|\b\d{2}\b)/i.test(query);
if (!hasModelHint) {
  return 'Para calcular cuotas exactas decime el modelo y la capacidad (por ejemplo: A56 8+256 o A56 12+256). No necesito códigos internos.';
}

return `Reglas de cuotas (cliente en Salta Capital):
- Cuotas disponibles SOLO presencial en Salta Capital
- 6 cuotas fijas (no hay 3, 9, 12 ni otras opciones)
- Aceptamos TODAS las tarjetas bancarizadas en 6 cuotas fijas EXCEPTO Naranja y SubCrédito
- Macro tiene precios especiales con cuotas propias (usá los montos del catálogo)
- NO trabajamos con Naranja ni SubCrédito bajo ninguna circunstancia
- El cliente debe venir al local: Caseros 1365, Salta Capital
- Siempre destacar primero el precio de contado como opción principal`;

// Process AI Response v15 - Parse metadata, clean text, handle images, build ManyChat payload
const aiOutput = $input.first().json;
const mergedData = $('Merge & Aggregate Messages').first().json;
const contextData = $('Orchestrator').first().json;

const normalize = (value) => String(value || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9\s_-]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const escapeRegExp = (value) => String(value).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

const parseProducts = (rawValue) => {
  const raw = String(rawValue ?? '').trim();
  if (!raw || raw.toLowerCase() === 'none') return [];
  const cleaned = raw.replace(/^\[/, '').replace(/\]$/, '').replace(/["']/g, '');
  const pieces = cleaned.split(/[,;|\n]/)
    .map((p) => p.trim().toLowerCase())
    .filter(Boolean)
    .filter((p) => p !== 'none')
    .filter((p) => /^[a-z0-9_-]+$/i.test(p));
  return [...new Set(pieces)];
};

const scoreToken = (token) => (/[a-z]*\d+[a-z]*/.test(token) ? 4 : 1);

const productImagesMap = contextData.product_images || {};
const productKeyNameMap = contextData.product_key_name_map || {};
const productStockMap = contextData.product_stock_map || {};

const allProductKeys = [...new Set([
  ...Object.keys(productKeyNameMap),
  ...Object.keys(productStockMap),
  ...Object.keys(productImagesMap),
])];

const catalog = allProductKeys.map((key) => ({
  key,
  keyNorm: normalize(key),
  name: String(productKeyNameMap[key] || key).trim(),
  nameNorm: normalize(productKeyNameMap[key] || ''),
  inStock: productStockMap[key],
  imageUrl: String(productImagesMap[key] || '').trim(),
}));

const keyAliasPairs = Object.entries(productKeyNameMap).flatMap(([key, name]) => {
  const human = String(name || key).trim();
  const variants = [key, key.replace(/_/g, '-'), key.replace(/-/g, '_')];
  return [...new Set(variants)].map((variant) => ({ alias: variant, human }));
});

const sanitizeInternalIds = (text) => {
  let out = String(text || '');
  out = out
    .replace(/\bError:\s*/gi, '')
    .replace(/product[_\s-]?keys?/gi, 'modelos')
    .replace(/c[o\u00f3]digos?\s+internos?/gi, 'modelos')
    .replace(/`([^`]+)`/g, '$1');
  for (const pair of keyAliasPairs) {
    const re = new RegExp('\\b' + escapeRegExp(pair.alias) + '\\b', 'gi');
    out = out.replace(re, pair.human);
  }
  out = out.replace(/\b[a-z0-9]+(?:[-_][a-z0-9]+){3,}\b/gi, 'ese modelo');
  return out.replace(/\s{2,}/g, ' ').trim();
};

const resolveProductKey = (candidateRaw) => {
  const candidate = normalize(candidateRaw);
  if (!candidate) return null;
  const exact = catalog.find((p) => p.keyNorm === candidate);
  if (exact) return exact.key;
  const starts = catalog.filter((p) => p.keyNorm.startsWith(candidate));
  if (starts.length === 1) return starts[0].key;
  const partial = catalog
    .map((p) => {
      let score = 0;
      if (p.keyNorm.includes(candidate)) score += 5;
      if (p.nameNorm.includes(candidate)) score += 4;
      return { key: p.key, score };
    })
    .filter((x) => x.score > 0)
    .sort((a, b) => b.score - a.score || a.key.length - b.key.length);
  return partial.length > 0 ? partial[0].key : null;
};

const inferProductKeysFromText = (text, limit = 3) => {
  const t = normalize(text);
  if (!t) return [];
  const tokens = [...new Set(
    t.split(/\s+/).map((w) => w.trim()).filter((w) => w.length >= 3 || /[a-z]*\d+[a-z]*/.test(w))
  )];
  const scored = catalog.map((p) => {
    let score = 0;
    if (t.includes(p.keyNorm)) score += 12;
    if (p.nameNorm && t.includes(p.nameNorm)) score += 10;
    for (const token of tokens) {
      const tokenScore = scoreToken(token);
      if (p.keyNorm.includes(token)) score += tokenScore;
      if (p.nameNorm.includes(token)) score += tokenScore;
    }
    if (p.inStock === false) score -= 2;
    return { key: p.key, score };
  });
  return scored.filter((x) => x.score >= 4).sort((a, b) => b.score - a.score).slice(0, limit).map((x) => x.key);
};

const unique = (arr) => [...new Set(arr.filter(Boolean))];

let responseText = aiOutput.output || aiOutput.text || 'Disculp\u00e1, hubo un error. \u00bfPod\u00e9s repetir tu consulta?';

const isSilent = responseText.trim() === '[SILENT]' || responseText.includes('[SILENT]');
if (isSilent) {
  return [{
    json: {
      is_silent: true,
      payload: null,
      needs_human: false,
      clean_text: '',
      metadata: { intent: 'followup', funnel_update: 'no_change', products: 'none' },
      products_list: [],
      subscriber_id: mergedData.subscriber_id,
      user_message: mergedData.user_message,
      was_audio: mergedData.was_audio,
      customer_id: contextData.customer_id,
      current_funnel_stage: contextData.customer_profile?.funnel_stage || null
    }
  }];
}

let metadata = {};
const metaFields = ['intent', 'products', 'funnel_update', 'city_detected', 'is_salta', 'brand_interest', 'budget_hint'];
const metaMatch = responseText.match(/---METADATA---(.*?)---END_METADATA---/s);
if (metaMatch) {
  const metaLines = metaMatch[1].trim().split('\n');
  for (const line of metaLines) {
    const [key, ...valueParts] = line.split(':');
    if (key && valueParts.length > 0) {
      metadata[key.trim()] = valueParts.join(':').trim();
    }
  }
} else {
  // Fallback: parse loose metadata (no proper delimiters)
  const looseMatch = responseText.match(/(?:^|\n)\s*-{2,}\s*\n?\s*intent:\s*(\S+)/s)
    || responseText.match(/(?:^|\n)\s*intent:\s*(\S+)\s*\n\s*(?:products|funnel_update)/s);
  if (looseMatch) {
    const startIdx = responseText.indexOf(looseMatch[0]);
    const metaBlock = responseText.slice(startIdx);
    for (const field of metaFields) {
      const fm = metaBlock.match(new RegExp(field + '\\s*:\\s*(.+)', 'i'));
      if (fm) metadata[field] = fm[1].trim();
    }
  }
}

const needsHuman = responseText.includes('[HUMAN]');

let cleanText = responseText
  .replace(/---METADATA---[\s\S]*?---END_METADATA---/g, '')
  .replace(/\[HUMAN\]/g, '')
  .replace(/\*\*/g, '')
  .replace(/\*/g, '')
  .replace(/^#+\s/gm, '')
  .replace(/```[\s\S]*?```/g, '')
  .replace(/\s*[:：]?\s*products:\s*\[[^\]]*\]/gi, '')
  .replace(/\s*products:\s*\[[^\]]*\]/gi, '')
  .replace(/\s*products:\s*[^\n]+/gi, '')
  .replace(/en\s*\[info_tienda[^\]]*\]/gi, '\ud83d\udccd Caseros 1365, Salta Capital. Diagonal a OCA.')
  .replace(/\[info_tienda[^\]]*\]/gi, '\ud83d\udccd Caseros 1365, Salta Capital. Diagonal a OCA.')
  .replace(/\[calcular_cuotas[^\]]*\]/gi, '')
  .replace(/\[\w+_?\w*\s*:[^\]]*\]/g, '')
  .replace(/,?\s*en\s*\.\s*,?/gi, '. ')
  .replace(/\s*-{2,}\s*\n?\s*intent:[\s\S]*$/g, '')
  .replace(/\n\s*intent:\s*\S+\s*\n\s*(?:products|funnel_update)[\s\S]*$/g, '')
  .replace(/\n\s*intent:\s*\S+\s*(?:funnel_update|products)[\s\S]*$/g, '')
  .replace(/\s*intent:\s*(?:greeting|price_inquiry|stock_check|comparison|purchase_intent|cuotas_inquiry|shipping_inquiry|complaint|off_topic|followup|ambiguous)\b[\s\S]*$/gi, '')
  .replace(/\s{2,}/g, ' ')
  .trim();

cleanText = sanitizeInternalIds(cleanText);
if (!cleanText) cleanText = 'Disculp\u00e1, \u00bfme repet\u00eds la consulta?';

const MAX_CHARS = 1600;
const MAX_MESSAGES = 8;

const splitTextSafely = (text, maxChars = MAX_CHARS, maxMessages = MAX_MESSAGES) => {
  const normalized = String(text || '').replace(/\r/g, '').trim();
  if (!normalized) return [];
  const sentenceParts = normalized.split(/\n+/).flatMap((part) => part.split(/(?<=[.!?])\s+/)).map((p) => p.trim()).filter(Boolean);
  const chunks = [];
  let current = '';
  const pushCurrent = () => { if (current && current.trim()) chunks.push(current.trim()); current = ''; };
  const appendPiece = (piece) => {
    if (!piece) return;
    if (!current) { current = piece; return; }
    if ((current.length + 1 + piece.length) <= maxChars) { current += ' ' + piece; }
    else { pushCurrent(); current = piece; }
  };
  for (const part of sentenceParts) {
    if (part.length <= maxChars) { appendPiece(part); continue; }
    const words = part.split(/\s+/).filter(Boolean);
    let local = '';
    const pushLocal = () => { if (local) appendPiece(local.trim()); local = ''; };
    for (const word of words) {
      if (word.length > maxChars) { pushLocal(); for (let i = 0; i < word.length; i += maxChars) appendPiece(word.slice(i, i + maxChars)); continue; }
      if (!local) local = word;
      else if ((local.length + 1 + word.length) <= maxChars) local += ' ' + word;
      else { pushLocal(); local = word; }
    }
    pushLocal();
  }
  pushCurrent();
  if (chunks.length <= maxMessages) return chunks;
  const trimmed = chunks.slice(0, maxMessages);
  const note = '... Si quer\u00e9s, te paso por marca (iPhone, Samsung o Redmi/POCO) para que sea m\u00e1s claro \ud83d\udc4c';
  const last = trimmed[trimmed.length - 1] || '';
  const allowed = maxChars - note.length - 1;
  trimmed[trimmed.length - 1] = (allowed > 50 ? last.slice(0, allowed).trim() : last.slice(0, maxChars - 1).trim()) + '\n' + note;
  return trimmed;
};

const splitByBrandSections = (text) => {
  const headingRegex = /(iPhone:|Samsung:|Redmi\/POCO:|Redmi\/Poco:|Xiaomi:)/gi;
  const matches2 = [...String(text || '').matchAll(headingRegex)];
  if (matches2.length < 2) return null;
  const sections = [];
  const intro = text.slice(0, matches2[0].index).trim();
  if (intro) sections.push(intro);
  for (let i = 0; i < matches2.length; i++) {
    const start = matches2[i].index;
    const end = i + 1 < matches2.length ? matches2[i + 1].index : text.length;
    const section = text.slice(start, end).trim();
    if (section) sections.push(section);
  }
  return sections;
};

const userMsg = String(mergedData.user_message || '');
const explicitlyAskedForImage = /foto|fotos|imagen|im\u00e1gen|im\u00e1genes|imagenes|mostrame|mostr\u00e1|ver.*(foto|imagen)|mandame|env\u00edame|envia|quiero ver|photo|picture|foto del|foto de la/i.test(userMsg);
const askedFullCatalog = /(todos|todo el|catalogo completo|cat[a\u00e1]logo completo|lista completa|android y iphone|iphone y android|todas las marcas|ver todo|mostrar todo)/i.test(userMsg);

const metadataCandidates = parseProducts(metadata.products);
let normalizedProducts = metadataCandidates.map((candidate) => resolveProductKey(candidate)).filter(Boolean);

if (explicitlyAskedForImage && normalizedProducts.length === 0) {
  const inferredFromUser = inferProductKeysFromText(userMsg, 3);
  const inferredFromBot = inferProductKeysFromText(cleanText, 3);
  normalizedProducts = unique([...inferredFromUser, ...inferredFromBot]);
}

metadata.products = normalizedProducts.length > 0 ? normalizedProducts.join(', ') : 'none';

let textChunks = splitTextSafely(cleanText, MAX_CHARS, MAX_MESSAGES);
if (askedFullCatalog) {
  const sections = splitByBrandSections(cleanText);
  if (sections && sections.length >= 2) {
    const branded = [];
    for (const sec of sections) {
      const secChunks = splitTextSafely(sec, MAX_CHARS, 2);
      branded.push(...secChunks);
    }
    if (branded.length > 0) textChunks = branded.slice(0, MAX_MESSAGES);
  }
}

let messagesArray = textChunks.length > 0
  ? textChunks.map((chunk) => ({ type: 'text', text: sanitizeInternalIds(chunk) }))
  : [{ type: 'text', text: 'Disculp\u00e1, \u00bfme repet\u00eds la consulta?' }];

if (explicitlyAskedForImage && normalizedProducts.length === 0) {
  const profileKey = resolveProductKey(contextData.customer_profile?.interested_product || '');
  const inStockImageKeys = catalog.filter((p) => p.imageUrl && p.inStock !== false).map((p) => p.key);
  const fallbackImageKeys = catalog.filter((p) => p.imageUrl).map((p) => p.key);
  const suggestionKeys = unique([profileKey, ...inStockImageKeys.slice(0, 6), ...fallbackImageKeys.slice(0, 6)]).slice(0, 4);
  if (suggestionKeys.length > 0) {
    const suggestionNames = suggestionKeys.map((key) => {
      const item = catalog.find((p) => p.key === key);
      return item ? item.name : key;
    });
    const suggestionMsg = '\n\n\ud83d\udcf8 Tengo fotos de: ' + suggestionNames.join(', ') + '. Decime cu\u00e1l quer\u00e9s y te la mando.';
    if (!/tengo fotos de|no tengo fotos/i.test(cleanText)) {
      cleanText = sanitizeInternalIds(cleanText.trim() + suggestionMsg);
      const textItem = messagesArray.find((m) => m.type === 'text');
      if (textItem) textItem.text = cleanText;
    }
  } else {
    const noImgGeneric = '\n\n\u26a0\ufe0f Por ahora no tengo fotos cargadas para enviarte, pero te paso precio y detalles si quer\u00e9s.';
    if (!/no tengo|no tenemos/i.test(cleanText)) {
      cleanText = sanitizeInternalIds(cleanText.trim() + noImgGeneric);
      const textItem = messagesArray.find((m) => m.type === 'text');
      if (textItem) textItem.text = cleanText;
    }
  }
}

if (explicitlyAskedForImage && normalizedProducts.length > 0) {
  const sentKeys = new Set();
  const sentUrls = new Set();
  const keysWithoutImage = [];
  for (const key of normalizedProducts) {
    const item = catalog.find((p) => p.key === key);
    const imageUrl = item?.imageUrl || '';
    if (imageUrl && !sentKeys.has(key) && !sentUrls.has(imageUrl)) {
      messagesArray.push({ type: 'image', url: imageUrl, image_url: imageUrl });
      sentKeys.add(key);
      sentUrls.add(imageUrl);
    } else if (!imageUrl) {
      keysWithoutImage.push(key);
    }
  }
  if (keysWithoutImage.length > 0 && !/no tengo|no tenemos/i.test(cleanText)) {
    const readable = keysWithoutImage.slice(0, 3).map((key) => {
      const item = catalog.find((p) => p.key === key);
      return item ? item.name : key;
    });
    const noImgNote = '\n\n\u26a0\ufe0f No tengo fotos de ' + readable.join(', ') + ' por el momento. Si quer\u00e9s m\u00e1s info del modelo escribime.';
    cleanText = sanitizeInternalIds(cleanText.trim() + noImgNote);
    const textItem = messagesArray.find((m) => m.type === 'text');
    if (textItem) textItem.text = cleanText;
  }
}

const payload = {
  subscriber_id: mergedData.subscriber_id,
  data: {
    version: 'v2',
    content: {
      type: 'whatsapp',
      messages: messagesArray
    }
  }
};

return [{
  json: {
    is_silent: false,
    payload,
    needs_human: needsHuman,
    clean_text: cleanText,
    metadata,
    products_list: normalizedProducts,
    subscriber_id: mergedData.subscriber_id,
    user_message: mergedData.user_message,
    was_audio: mergedData.was_audio,
    customer_id: contextData.customer_id,
    current_funnel_stage: contextData.customer_profile?.funnel_stage || null
  }
}];

const data = $('Merge All Routes').first().json;
const metadata = data.metadata || {};
const products = Array.isArray(data.products_list) ? data.products_list : [];

return [{
  json: {
    manychat_id: data.subscriber_id,
    customer_id: data.customer_id || null,
    role: 'bot',
    message: data.clean_text || '(solo imágenes)',
    message_type: 'text',
    intent_detected: metadata.intent || null,
    products_mentioned: products,
    triggered_human: data.needs_human || false,
    was_audio: false
  }
}];

const data = $('Merge All Routes').first().json;
const metadata = data.metadata || {};
const products = Array.isArray(data.products_list) ? data.products_list : [];

const stageRank = {
  new: 0,
  browsing: 1,
  interested: 2,
  closing: 3,
  human_handoff: 4
};

const currentStage = String(data.current_funnel_stage || '').trim().toLowerCase();
const requestedStage = String(metadata.funnel_update || '').trim().toLowerCase();

const updates = {
  last_bot_interaction: new Date().toISOString(),
  updated_at: new Date().toISOString()
};

if (requestedStage && requestedStage !== 'no_change') {
  if (stageRank[requestedStage] !== undefined) {
    if (stageRank[currentStage] === undefined || stageRank[requestedStage] >= stageRank[currentStage]) {
      updates.funnel_stage = requestedStage;
    }
  }
}

if (metadata.city_detected && metadata.city_detected !== 'none') {
  let city = metadata.city_detected.trim();
  const lower = city.toLowerCase();
  if (['salta', 'salta capital', 'salta cap'].includes(lower)) {
    city = 'Salta Capital';
    updates.is_salta_capital = true;
  }
  updates.city = city;
}

if (metadata.is_salta === 'true') updates.is_salta_capital = true;
else if (metadata.is_salta === 'false') updates.is_salta_capital = false;

if (metadata.brand_interest && metadata.brand_interest !== 'none') updates.preferred_brand = metadata.brand_interest;
if (metadata.budget_hint && metadata.budget_hint !== 'none') updates.preferred_budget = metadata.budget_hint;
if (products.length > 0) updates.interested_product = products[0];

if (data.needs_human) {
  updates.human_assigned = true;
  updates.funnel_stage = 'human_handoff';
}

return [{ json: { subscriber_id: data.subscriber_id, updates } }];

const data = $('Merge All Routes').first().json;
const metadata = data.metadata || {};

const saveNode = $('Save Incoming Message').first();
let savedId = null;
const savedBody = saveNode.json;
if (Array.isArray(savedBody) && savedBody.length > 0) {
  savedId = savedBody[0]?.id;
} else if (savedBody && savedBody.id) {
  savedId = savedBody.id;
}

const intent = String(metadata.intent || '').trim();
if (!savedId || !intent) {
  return [];
}

return [{
  json: {
    message_id: savedId,
    intent
  }
}];

const upsertRaw = $input.first().json;

const toIntOrNull = (value) => {
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
};

const extractCustomerId = (raw) => {
  if (typeof raw === 'number' && Number.isFinite(raw)) return raw;
  if (typeof raw === 'string') return toIntOrNull(raw);
  if (Array.isArray(raw) && raw.length > 0) {
    const first = raw[0];
    if (typeof first === 'number' && Number.isFinite(first)) return first;
    if (typeof first === 'string') return toIntOrNull(first);
    if (first && typeof first === 'object') {
      if (first.upsert_customer !== undefined && first.upsert_customer !== null) return toIntOrNull(first.upsert_customer);
      if (first.customer_id !== undefined && first.customer_id !== null) return toIntOrNull(first.customer_id);
      if (first.id !== undefined && first.id !== null) return toIntOrNull(first.id);
    }
  }
  if (raw && typeof raw === 'object') {
    if (raw.upsert_customer !== undefined && raw.upsert_customer !== null) return toIntOrNull(raw.upsert_customer);
    if (raw.customer_id !== undefined && raw.customer_id !== null) return toIntOrNull(raw.customer_id);
    if (raw.id !== undefined && raw.id !== null) return toIntOrNull(raw.id);
  }
  return null;
};

const customerId = extractCustomerId(upsertRaw);

const saveNode = $('Save Incoming Message').first();
const savedBody = saveNode.json;
let messageId = null;
if (Array.isArray(savedBody) && savedBody.length > 0) {
  messageId = savedBody[0]?.id;
} else if (savedBody && savedBody.id) {
  messageId = savedBody.id;
}

const parsedMessageId = toIntOrNull(messageId);
if (!Number.isFinite(customerId) || !Number.isFinite(parsedMessageId)) {
  return [];
}

return [{
  json: {
    message_id: parsedMessageId,
    customer_id: customerId
  }
}];
